-- RawDrop catalog + admin schema (products, sections, site settings, admin auth)
-- Replaces the local JSON file store (data/store.json), which cannot persist on Cloudflare Workers.

CREATE TABLE IF NOT EXISTS sections (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  name TEXT NOT NULL,
  sort_order INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE IF NOT EXISTS products (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  name TEXT NOT NULL,
  slug TEXT UNIQUE,
  description TEXT NOT NULL DEFAULT '',
  price NUMERIC(12, 2) NOT NULL DEFAULT 0,
  image_url TEXT NOT NULL DEFAULT '',
  section_id INTEGER NOT NULL REFERENCES sections (id),
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_products_section_id ON products (section_id);

CREATE TABLE IF NOT EXISTS site_settings (
  id INTEGER PRIMARY KEY DEFAULT 1 CHECK (id = 1),
  store_name TEXT NOT NULL DEFAULT 'RawDrop',
  tagline TEXT NOT NULL DEFAULT '',
  products_page_title TEXT NOT NULL DEFAULT '',
  products_page_subtitle TEXT NOT NULL DEFAULT '',
  footer_text TEXT NOT NULL DEFAULT '',
  hero_title TEXT NOT NULL DEFAULT '',
  hero_subtitle TEXT NOT NULL DEFAULT '',
  hero_button_text TEXT NOT NULL DEFAULT '',
  hero_image_url TEXT NOT NULL DEFAULT '',
  about_title TEXT NOT NULL DEFAULT '',
  about_text TEXT NOT NULL DEFAULT '',
  contact_email TEXT NOT NULL DEFAULT '',
  contact_phone TEXT NOT NULL DEFAULT '',
  testimonial_1_name TEXT NOT NULL DEFAULT '',
  testimonial_1_text TEXT NOT NULL DEFAULT '',
  testimonial_2_name TEXT NOT NULL DEFAULT '',
  testimonial_2_text TEXT NOT NULL DEFAULT '',
  testimonial_3_name TEXT NOT NULL DEFAULT '',
  testimonial_3_text TEXT NOT NULL DEFAULT '',
  btc_wallet_address TEXT NOT NULL DEFAULT '',
  btc_payment_enabled BOOLEAN NOT NULL DEFAULT FALSE,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS admin_users (
  username TEXT PRIMARY KEY,
  password_hash TEXT NOT NULL
);

ALTER TABLE sections ENABLE ROW LEVEL SECURITY;
ALTER TABLE products ENABLE ROW LEVEL SECURITY;
ALTER TABLE site_settings ENABLE ROW LEVEL SECURITY;
ALTER TABLE admin_users ENABLE ROW LEVEL SECURITY;
-- No policies defined: only the service_role key (used server-side) can read/write these
-- tables; the anon/publishable key gets zero access since RLS defaults to deny-all.

