-- Seed: products
INSERT INTO products (id, name, slug, description, price, image_url, section_id, created_at) VALUES
  (1, 'Essential Cotton Tee — White', 'essential-cotton-tee-white-1', 'A wardrobe staple crafted from soft, breathable cotton. Relaxed fit with reinforced stitching for everyday wear. Machine washable. Available for customization in your dashboard.', 200, 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=600&h=600&fit=crop', 1, '2026-07-02T13:02:30.292Z'),
  (2, 'Slim Fit Denim Jacket', 'slim-fit-denim-jacket-2', 'Classic denim jacket with a modern slim silhouette. Durable wash, metal hardware, and functional chest pockets. Layer over any outfit for a polished casual look.', 200, 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&h=600&fit=crop', 1, '2026-07-02T13:02:30.294Z'),
  (3, 'Minimalist Watch — Silver', 'minimalist-watch-silver-3', 'Clean analog design with a stainless steel case and adjustable link band. Water-resistant for daily use. Includes presentation box — ideal for gifting.', 200, 'https://images.unsplash.com/photo-1572635196237-14b3f281503f?w=600&h=600&fit=crop', 1, '2026-07-02T13:02:30.294Z'),
  (4, 'Everyday Crossbody Bag', 'everyday-crossbody-bag-4', 'Compact crossbody with adjustable strap, interior zip pocket, and secure magnetic closure. Fits phone, wallet, and essentials. Lightweight for all-day carry.', 200, 'https://images.unsplash.com/photo-1560343090-f0409e92703a?w=600&h=600&fit=crop', 1, '2026-07-02T13:02:30.294Z'),
  (5, 'Performance Running Cap', 'performance-running-cap-5', 'Lightweight cap with moisture-wicking fabric and adjustable back strap. UV protection for outdoor training. One size fits most.', 200, 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&h=600&fit=crop', 1, '2026-07-02T13:02:30.294Z'),
  (6, 'Wireless Earbuds Pro', 'wireless-earbuds-pro-6', 'True wireless earbuds with active noise cancellation, 24-hour battery life with case, and touch controls. Includes three ear tip sizes for a secure fit.', 200, 'https://images.unsplash.com/photo-1546868871-7041f69a55b0?w=600&h=600&fit=crop', 2, '2026-07-02T13:02:30.294Z'),
  (7, 'Insulated Water Bottle — 32oz', 'insulated-water-bottle-32oz-7', 'Double-wall vacuum insulation keeps drinks cold 24 hours or hot 12 hours. BPA-free stainless steel, leak-proof lid, fits standard cup holders.', 200, 'https://images.unsplash.com/photo-1585386959984-a41552231654?w=600&h=600&fit=crop', 2, '2026-07-02T13:02:30.294Z'),
  (8, 'Organic Face Moisturizer', 'organic-face-moisturizer-8', 'Daily moisturizer with hyaluronic acid and vitamin E. Lightweight, non-greasy formula suitable for all skin types. Dermatologist tested, fragrance-free.', 200, 'https://images.unsplash.com/photo-1565814636199-ae8133055c1c?w=600&h=600&fit=crop', 2, '2026-07-02T13:02:30.294Z'),
  (9, 'Leather Belt — Brown', 'leather-belt-brown-9', 'Full-grain leather belt with brushed nickel buckle. 1.25-inch width, suitable for casual and business attire. Available in standard waist sizes.', 200, 'https://images.unsplash.com/photo-1491553895911-0055eca6402d?w=600&h=600&fit=crop', 2, '2026-07-02T13:02:30.294Z'),
  (10, 'Portable Phone Charger 10K', 'portable-phone-charger-10k-10', '10,000mAh power bank with USB-C and USB-A outputs. Fast-charge compatible. LED indicator shows remaining power. TSA-approved for travel.', 200, 'https://images.unsplash.com/photo-1526170375885-4d8ecf77b99f?w=600&h=600&fit=crop', 2, '2026-07-02T13:02:30.294Z'),
  (11, 'Bluetooth Speaker — Outdoor', 'bluetooth-speaker-outdoor-11', 'Rugged wireless speaker with 360° sound and 12-hour playtime. IPX7 waterproof rating. Built-in microphone for hands-free calls.', 200, 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=600&h=600&fit=crop', 3, '2026-07-02T13:02:30.294Z'),
  (12, 'USB-C Hub — 7-in-1', 'usb-c-hub-7-in-1-12', 'Expand your laptop with HDMI, USB 3.0, SD card reader, and 100W pass-through charging. Aluminum body, plug-and-play — no drivers required.', 200, 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&h=600&fit=crop', 3, '2026-07-02T13:02:30.294Z'),
  (13, 'Smart LED Desk Lamp', 'smart-led-desk-lamp-13', 'Adjustable arm lamp with five brightness levels and three color temperatures. Touch controls, memory function, and energy-efficient LED panel.', 200, 'https://images.unsplash.com/photo-1572635196237-14b3f281503f?w=600&h=600&fit=crop', 3, '2026-07-02T13:02:30.294Z'),
  (14, 'Mechanical Keyboard — Compact', 'mechanical-keyboard-compact-14', '75% layout mechanical keyboard with hot-swappable switches and RGB backlight. PBT keycaps, USB-C connection. Ideal for work and gaming.', 200, 'https://images.unsplash.com/photo-1560343090-f0409e92703a?w=600&h=600&fit=crop', 3, '2026-07-02T13:02:30.294Z'),
  (15, '4K Action Camera', '4k-action-camera-15', 'Capture adventures in 4K at 30fps with electronic image stabilization. Waterproof case included. Wi-Fi transfer to smartphone app.', 200, 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&h=600&fit=crop', 3, '2026-07-02T13:02:30.294Z'),
  (16, 'Merino Wool Sweater — Navy', 'merino-wool-sweater-navy-16', 'Fine merino wool pullover that''s naturally temperature-regulating and odor-resistant. Ribbed cuffs and hem. Machine wash cold on gentle cycle.', 200, 'https://images.unsplash.com/photo-1546868871-7041f69a55b0?w=600&h=600&fit=crop', 4, '2026-07-02T13:02:30.294Z'),
  (17, 'Classic Chino Pants — Khaki', 'classic-chino-pants-khaki-17', 'Tailored chinos in stretch cotton twill. Mid-rise fit with slant pockets and welt back pockets. Versatile for office or weekend.', 200, 'https://images.unsplash.com/photo-1585386959984-a41552231654?w=600&h=600&fit=crop', 4, '2026-07-02T13:02:30.294Z'),
  (18, 'Canvas Low-Top Sneakers', 'canvas-low-top-sneakers-18', 'Timeless canvas sneakers with cushioned insole and vulcanized rubber sole. Lace-up closure. Pairs with jeans, shorts, or casual dresses.', 200, 'https://images.unsplash.com/photo-1565814636199-ae8133055c1c?w=600&h=600&fit=crop', 4, '2026-07-02T13:02:30.294Z'),
  (19, 'Polarized Sunglasses — Aviator', 'polarized-sunglasses-aviator-19', 'UV400 polarized lenses reduce glare and protect eyes. Lightweight metal frame with adjustable nose pads. Includes hard case and cleaning cloth.', 200, 'https://images.unsplash.com/photo-1491553895911-0055eca6402d?w=600&h=600&fit=crop', 4, '2026-07-02T13:02:30.294Z'),
  (20, 'Wool Blend Scarf — Charcoal', 'wool-blend-scarf-charcoal-20', 'Soft wool-acrylic blend scarf for cold weather. Generous length for multiple wrap styles. Fringed edges. Dry clean recommended.', 200, 'https://images.unsplash.com/photo-1526170375885-4d8ecf77b99f?w=600&h=600&fit=crop', 4, '2026-07-02T13:02:30.294Z'),
  (21, 'Ceramic Dinnerware Set — 16pc', 'ceramic-dinnerware-set-16pc-21', 'Service for four including dinner plates, salad plates, bowls, and mugs. Microwave and dishwasher safe. Modern matte glaze finish.', 200, 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=600&h=600&fit=crop', 5, '2026-07-02T13:02:30.294Z'),
  (22, 'Memory Foam Pillow', 'memory-foam-pillow-22', 'Contoured memory foam pillow supports neck alignment for side and back sleepers. Removable, washable bamboo-derived cover. CertiPUR-US certified foam.', 200, 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&h=600&fit=crop', 5, '2026-07-02T13:02:30.294Z'),
  (23, 'Scented Candle — Lavender', 'scented-candle-lavender-23', 'Hand-poured soy wax candle with cotton wick. Approximately 45-hour burn time. Natural lavender essential oil blend. Reusable glass jar.', 200, 'https://images.unsplash.com/photo-1572635196237-14b3f281503f?w=600&h=600&fit=crop', 5, '2026-07-02T13:02:30.294Z'),
  (24, 'Throw Blanket — Knit', 'throw-blanket-knit-24', 'Chunky knit throw blanket in soft acrylic yarn. 50×60 inches — perfect for sofas and beds. Machine washable. Adds warmth and texture to any room.', 200, 'https://images.unsplash.com/photo-1560343090-f0409e92703a?w=600&h=600&fit=crop', 5, '2026-07-02T13:02:30.294Z'),
  (25, 'Stainless Steel Cookware Set', 'stainless-steel-cookware-set-25', 'Three-piece set: 8-inch fry pan, 2-quart saucepan with lid, and 6-quart stockpot with lid. Tri-ply construction for even heating. Oven safe to 500°F.', 200, 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&h=600&fit=crop', 5, '2026-07-02T13:02:30.294Z'),
  (26, 'Vitamin C Serum — 1oz', 'vitamin-c-serum-1oz-26', 'Brightening serum with 15% L-ascorbic acid and ferulic acid. Apply morning before moisturizer and SPF. Visible results in 4–6 weeks with consistent use.', 200, 'https://images.unsplash.com/photo-1546868871-7041f69a55b0?w=600&h=600&fit=crop', 6, '2026-07-02T13:02:30.294Z'),
  (27, 'Electric Toothbrush Kit', 'electric-toothbrush-kit-27', 'Sonic toothbrush with two-minute timer and three cleaning modes. Includes charging base and two replacement heads. ADA accepted.', 200, 'https://images.unsplash.com/photo-1585386959984-a41552231654?w=600&h=600&fit=crop', 6, '2026-07-02T13:02:30.294Z'),
  (28, 'Hair Styling Clay — Matte', 'hair-styling-clay-matte-28', 'Medium-hold matte clay for textured, natural-looking styles. Water-based formula washes out easily. Works on short to medium hair lengths.', 200, 'https://images.unsplash.com/photo-1565814636199-ae8133055c1c?w=600&h=600&fit=crop', 6, '2026-07-02T13:02:30.294Z'),
  (29, 'Body Wash — Eucalyptus', 'body-wash-eucalyptus-29', 'Plant-derived body wash with eucalyptus and mint. Sulfate-free, gentle on skin. Large 16oz bottle with pump dispenser.', 200, 'https://images.unsplash.com/photo-1491553895911-0055eca6402d?w=600&h=600&fit=crop', 6, '2026-07-02T13:02:30.294Z'),
  (30, 'Grooming Kit — Travel', 'grooming-kit-travel-30', 'TSA-friendly grooming set: nail clipper, tweezers, scissors, and comb in a zippered leather case. Essential tools for travel or daily use.', 200, 'https://images.unsplash.com/photo-1526170375885-4d8ecf77b99f?w=600&h=600&fit=crop', 6, '2026-07-02T13:02:30.294Z'),
  (31, 'Yoga Mat — 6mm Extra Thick', 'yoga-mat-6mm-extra-thick-31', 'Non-slip TPE yoga mat with carrying strap. 6mm cushioning protects joints during floor work. Free of latex, PVC, and phthalates.', 150, 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=600&h=600&fit=crop', 7, '2026-07-02T13:02:30.294Z'),
  (32, 'Resistance Bands Set', 'resistance-bands-set-32', 'Five color-coded bands from light to heavy resistance. Includes door anchor, handles, and ankle straps. Full-body workout guide included.', 150, 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&h=600&fit=crop', 7, '2026-07-02T13:02:30.294Z'),
  (33, 'Camping Headlamp — Rechargeable', 'camping-headlamp-rechargeable-33', 'LED headlamp with 300-lumen max output and red night-vision mode. USB rechargeable, 40-hour runtime on low. IPX4 splash resistant.', 150, 'https://images.unsplash.com/photo-1572635196237-14b3f281503f?w=600&h=600&fit=crop', 7, '2026-07-02T13:02:30.294Z'),
  (34, 'Stainless Steel Flask — 8oz', 'stainless-steel-flask-8oz-34', 'Vacuum-insulated flask keeps beverages hot or cold for hours. Leak-proof cap, slim profile fits pockets and bags. Food-grade 18/8 steel.', 150, 'https://images.unsplash.com/photo-1560343090-f0409e92703a?w=600&h=600&fit=crop', 7, '2026-07-02T13:02:30.294Z'),
