  (37, 'Travel Duffel Bag — 40L', 'travel-duffel-bag-40l-37', 'Durable canvas duffel with reinforced handles and removable shoulder strap. Interior zip pocket. Fits overhead bin requirements on most airlines.', 150, 'https://images.unsplash.com/photo-1585386959984-a41552231654?w=600&h=600&fit=crop', 8, '2026-07-02T13:02:30.294Z'),
