  (40, 'Laptop Sleeve — 15 inch', 'laptop-sleeve-15-inch-40', 'Padded neoprene sleeve protects laptops up to 15.6 inches. Slim design slides into backpacks and briefcases. Zippered front pocket for cables.', 150, 'https://images.unsplash.com/photo-1526170375885-4d8ecf77b99f?w=600&h=600&fit=crop', 8, '2026-07-02T13:02:30.294Z'),
