  (48, 'Outlet — Canvas Tote Bag', 'outlet-canvas-tote-bag-48', 'Heavy-duty canvas tote with interior pocket and reinforced handles. Ideal for groceries, gym, or daily errands. While supplies last.', 200, 'https://images.unsplash.com/photo-1565814636199-ae8133055c1c?w=600&h=600&fit=crop', 9, '2026-07-02T13:02:30.294Z'),
